      const start = Date.now();
      const method = request.method;

      const response = await apiApp.fetch(request, envParam, cf);

      const duration = (Date.now() - start) / 1000;
      const status = String(response.status);

      incrementCounter(pathname, method, status);
      observeDuration(pathname, method, status, duration);

      return response;
    }

    // All other routes go through the main app (which has metrics middleware)
    const start = Date.now();
    const method = request.method;

    const response = await app.fetch(request, envParam, cf);

    const duration = (Date.now() - start) / 1000;
    const status = String(response.status);

    // Use the raw pathname as the path label (for 404s, this is the actual path)
    incrementCounter(pathname, method, status);
    observeDuration(pathname, method, status, duration);

    return response;
  },
